sql:
SELECT election_id, COUNT(voter_id) AS total_voters
FROM election_participation
GROUP BY election_id;

external_knowledge:
- "big" refers to elections with more than 500,000 voters; 
- "concluded" refers to elections with a status of 'Completed'; 
- "dominant party" refers to the party with a unique identifier of '0'.

sql:
SELECT COUNT(voter_id) AS total_voters
FROM election_participation
WHERE election_id = 1;
